### React 19 form state integration

FormField integrates seamlessly with React 19's built-in form state features, including `useActionState` for progressive enhancement and server-side validation. This example demonstrates the standard React 19 pattern where validation occurs on form submission:

```jsx-live-dev
const App = () => {
  const [state, submitAction, isPending] = React.useActionState(
    async (previousState, formData) => {
      // Simulate async server-side validation
      await new Promise(resolve => setTimeout(resolve, 1000));

      const errors = {};
      const email = formData.get('email');
      const password = formData.get('password');

      if (!email) {
        errors.email = 'Email is required';
      } else if (!/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i.test(email)) {
        errors.email = 'Invalid email address';
      }

      if (!password) {
        errors.password = 'Password is required';
      } else if (password.length < 8) {
        errors.password = 'Password must be at least 8 characters';
      }

      if (Object.keys(errors).length > 0) {
        return { success: false, errors, data: null };
      }

      return {
        success: true,
        message: 'Login successful!',
        data: { email, password: '••••••••' },
        errors: {}
      };
    },
    { success: false, errors: {}, data: null }
  );

  return (
    <form action={submitAction} noValidate>
      <Stack direction="column" gap="500">
        <FormField.Root
          isRequired
          isInvalid={!!(state.errors && state.errors.email)}
        >
          <FormField.Label>Email Address</FormField.Label>
          <FormField.Input>
            <TextInput
              type="email"
              name="email"
              placeholder="your@email.com"
              autoComplete="email"
            />
          </FormField.Input>
          <FormField.Error>{state.errors?.email}</FormField.Error>
        </FormField.Root>

        <FormField.Root
          isRequired
          isInvalid={!!(state.errors && state.errors.password)}
        >
          <FormField.Label>Password</FormField.Label>
          <FormField.Input>
            <PasswordInput
              name="password"
              placeholder="Enter password"
              autoComplete="current-password"
            />
          </FormField.Input>
          <FormField.Description>Minimum 8 characters</FormField.Description>
          <FormField.Error>{state.errors?.password}</FormField.Error>
        </FormField.Root>

        <Button type="submit" isDisabled={isPending}>
          {isPending ? 'Logging in...' : 'Log In'}
        </Button>

        {state.success && state.data && (
          <Alert.Root colorPalette="positive">
            <Alert.Title>{state.message}</Alert.Title>
            <Alert.Description>
              Email: {state.data.email}
            </Alert.Description>
          </Alert.Root>
        )}
      </Stack>
    </form>
  );
};
```

## Testing your implementation

These examples demonstrate how to test your implementation when using FormField within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify FormField renders with all parts correctly structured

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import React from "react";
import { FormField, TextInput, NimbusProvider } from "@commercetools/nimbus";

describe("FormField - Basic rendering", () => {
  it("renders with label and input", () => {
    render(
      <NimbusProvider>
        <FormField.Root>
          <FormField.Label>Username</FormField.Label>
          <FormField.Input>
            <TextInput placeholder="Enter username" />
          </FormField.Input>
        </FormField.Root>
      </NimbusProvider>
    );

    expect(screen.getByText("Username")).toBeInTheDocument();
    expect(screen.getByPlaceholderText("Enter username")).toBeInTheDocument();
  });

  it("renders with description", () => {
    render(
      <NimbusProvider>
        <FormField.Root>
          <FormField.Label>Password</FormField.Label>
          <FormField.Input>
            <TextInput type="password" />
          </FormField.Input>
          <FormField.Description>
            Must be at least 8 characters
          </FormField.Description>
        </FormField.Root>
      </NimbusProvider>
    );

    expect(
      screen.getByText("Must be at least 8 characters")
    ).toBeInTheDocument();
  });

  it("renders with all parts", () => {
    render(
      <NimbusProvider>
        <FormField.Root isInvalid>
          <FormField.Label>Email</FormField.Label>
          <FormField.Input>
            <TextInput type="email" />
          </FormField.Input>
          <FormField.Description>Your contact email</FormField.Description>
          <FormField.Error>Invalid email format</FormField.Error>
        </FormField.Root>
      </NimbusProvider>
    );

    expect(screen.getByText("Email")).toBeInTheDocument();
    expect(screen.getByText("Your contact email")).toBeInTheDocument();
    expect(screen.getByText("Invalid email format")).toBeInTheDocument();
  });
});
```

### Accessibility Tests

Verify ARIA attributes and label associations

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import React from "react";
import { FormField, TextInput, NimbusProvider } from "@commercetools/nimbus";

describe("FormField - Accessibility", () => {
  it("associates label with input via aria-labelledby", () => {
    render(
      <NimbusProvider>
        <FormField.Root>
          <FormField.Label>Username</FormField.Label>
          <FormField.Input>
            <TextInput />
          </FormField.Input>
        </FormField.Root>
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    const label = screen.getByText("Username");

    expect(input).toHaveAttribute("aria-labelledby", label.id);
  });

  it("associates description with input via aria-describedby", () => {
    render(
      <NimbusProvider>
        <FormField.Root>
          <FormField.Label>Username</FormField.Label>
          <FormField.Input>
            <TextInput />
          </FormField.Input>
          <FormField.Description>
            Must be at least 8 characters
          </FormField.Description>
        </FormField.Root>
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    const description = screen.getByText("Must be at least 8 characters");

    expect(input.getAttribute("aria-describedby")).toContain(description.id);
  });

  it("marks input as required when isRequired is true", () => {
    render(
      <NimbusProvider>
        <FormField.Root isRequired>
          <FormField.Label>Email</FormField.Label>
          <FormField.Input>
            <TextInput type="email" />
          </FormField.Input>
        </FormField.Root>
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    expect(input).toHaveAttribute("aria-required", "true");
  });

  it("marks input as invalid when isInvalid is true", () => {
    render(
