### User Interactions

Test user input and validation flows

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import React from "react";
import { FormField, TextInput, NimbusProvider } from "@commercetools/nimbus";

describe("FormField - User interactions", () => {
  it("handles user input", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <FormField.Root>
          <FormField.Label>Username</FormField.Label>
          <FormField.Input>
            <TextInput placeholder="Enter username" />
          </FormField.Input>
        </FormField.Root>
      </NimbusProvider>
    );

    const input = screen.getByRole("textbox");
    await user.type(input, "testuser");

    expect(input).toHaveValue("testuser");
  });

  it("supports validation on blur", async () => {
    const user = userEvent.setup();

    const TestComponent = () => {
      const [invalid, setInvalid] = React.useState(false);
      const [value, setValue] = React.useState("");

      const handleChange = (newValue: string) => {
        setValue(newValue);
      };

      const handleBlur = () => {
        setInvalid(value.length < 3);
      };

      return (
        <NimbusProvider>
          <FormField.Root isInvalid={invalid}>
            <FormField.Label>Username</FormField.Label>
            <FormField.Input>
              <TextInput
                value={value}
                onChange={handleChange}
                onBlur={handleBlur}
              />
            </FormField.Input>
            <FormField.Error>Must be at least 3 characters</FormField.Error>
          </FormField.Root>
        </NimbusProvider>
      );
    };

    render(<TestComponent />);

    const input = screen.getByRole("textbox");
    await user.type(input, "ab");
    await user.tab(); // Blur the input

    expect(
      screen.getByText("Must be at least 3 characters")
    ).toBeInTheDocument();
  });
});
